class Solution {
    public String smallestSubsequence(String s) {
        int[] count = new int[26];
        boolean[] inRes = new boolean[s.length()];
        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']++;
        }
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']--;
            if (inRes[i] || res.length() == 0 || s.charAt(i) >= res.charAt(res.length() - 1)) {
                continue;
            }
            while (res.length() > 0 && s.charAt(i) < res.charAt(res.length() - 1) && count[res.charAt(res.length() - 1) - 'a'] > 0) {
                inRes[res.length() - 1] = false;
                res.deleteCharAt(res.length() - 1);
            }
            res.append(s.charAt(i));
            inRes[i] = true;
        }
        return res.toString();
    }
}
